css:
@page { 
  size: A4 !important; 
  margin: 8mm 10mm 15mm 10mm !important; 
}

/* Conteneur principal */
.print-format, .print-format table, .bc, .bc table {
  margin: 0;
  padding: 0;
  border-collapse: collapse !important;
}

.bc { 
  font-family: Arial, sans-serif !important; 
  color: #222 !important; 
  font-size: 9.5pt !important; 
  width: 100% !important;
  position: relative !important;
  min-height: 262mm !important; /* Fixe le pied de page en bas de la page A4 */
}

/* En-tête */
.bc-head { 
  width: 100% !important; 
  margin-bottom: 12px !important; 
}

.bc-head td { 
  vertical-align: top !important; 
  padding: 0 !important; 
}

.bc-logo-cell { text-align: left !important; }
.bc-logo { 
  height: 44px !important; 
  width: auto !important; 
  max-width: 200px !important; 
  object-fit: contain !important; 
  display: block !important; 
  margin: 0 0 2px 0 !important; 
}

.bc-slogan { 
  color: #8a929b !important; 
  font-size: 8pt !important; 
  letter-spacing: 1px !important; 
  display: block !important; 
}

.bc-title { 
  text-align: right !important; 
  color: #2c3e50 !important; 
  font-weight: 300 !important; 
  line-height: 1.05 !important; 
}
.bc-title .l1 { font-size: 21pt !important; letter-spacing: 1px !important; }
.bc-title .l2 { font-size: 14pt !important; letter-spacing: 1px !important; }

/* Blocs d'informations supérieurs */
.bc-info { 
  width: 100% !important; 
  margin-bottom: 12px !important; 
}

.bc-grid { width: 100% !important; }
.bc-grid td { 
  border: 1px solid #c9ced4 !important; 
  padding: 3px 6px !important; 
  font-size: 8.5pt !important; 
}

.bc-grid .h {
  background: #2c3e50 !important; 
  color: #fff !important;
  -webkit-print-color-adjust: exact !important; 
  print-color-adjust: exact !important;
  font-weight: bold !important; 
  text-align: center !important; 
}

.bc-grid .v { 
  background: #f0f1f3 !important;
  -webkit-print-color-adjust: exact !important; 
  print-color-adjust: exact !important; 
  text-align: center !important; 
  height: 14px !important; 
}

.bc-lead { 
  margin: 0 0 6px 0 !important; 
  font-size: 9.5pt !important; 
}

/* Modification de la section Tableau (Conforme à l'image modèle) */
.bc-items { width: 100% !important; }
.bc-items th {
  background: #2c3e50 !important; 
  color: #fff !important;
  -webkit-print-color-adjust: exact !important; 
  print-color-adjust: exact !important;
  padding: 5px 6px !important; 
  font-size: 8.5pt !important; 
  text-align: center !important;
  border: 1px solid #c9ced4 !important;
}

.bc-items td { 
  border: 1px solid #c9ced4 !important; 
  padding: 4px 6px !important; 
  font-size: 9pt !important; 
  height: 16px !important; 
}
.bc-items .c { text-align: center !important; }
.bc-items .r { text-align: right !important; }

/* Totaux */
.bc-tot-wrapper {
  width: 100% !important;
  display: block !important;
  margin-top: -1px !important;
  margin-bottom: 15px !important;
}

.bc-tot { 
  width: 46% !important; 
  float: right !important; 
  border-collapse: collapse !important;
}

.bc-tot td { 
  border: 1px solid #c9ced4 !important; 
  padding: 4px 8px !important; 
  font-size: 9pt !important;
  background: #ececec !important;
  -webkit-print-color-adjust: exact !important; 
  print-color-adjust: exact !important; 
}
.bc-tot .lbl { text-align: right !important; font-weight: bold !important; width: 55% !important; }
.bc-tot .val { text-align: right !important; }
.bc-tot .ttc td { font-weight: bold !important; font-size: 10pt !important; }

/* Section Commentaire (Espace augmenté) */
.bc-sa { 
  color: #2c3e50 !important; 
  font-weight: bold !important; 
  font-size: 9.5pt !important; 
  border-top: 2px solid #c9ced4 !important; 
  padding-top: 5px !important; 
}

.bc-com {
  background: #2c3e50 !important; 
  color: #fff !important;
  -webkit-print-color-adjust: exact !important; 
  print-color-adjust: exact !important;
  text-align: center !important; 
  font-weight: bold !important; 
  font-size: 9pt !important; 
  padding: 5px !important; 
  margin-top: 4px !important;
}

.bc-com-box { 
  border: 1px solid #c9ced4 !important; 
  border-top: none !important; 
  padding: 12px 15px !important;
  min-height: 130px !important; /* Hauteur augmentée pour ajouter de l'espace */
  font-size: 9.5pt !important; 
}

/* Pied de page calé de manière absolue */
.bc-foot { 
  position: absolute !important;
  bottom: 0 !important;
  left: 0 !important;
  width: 100% !important;
  border-top: 1px solid #c9ced4 !important; 
  padding-top: 5px !important;
  text-align: center !important; 
  font-size: 7.5pt !important; 
  color: #555 !important; 
  line-height: 1.4 !important; 
}
